#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_BITS 31

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, X;
        scanf("%d %d", &N, &X);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < X; i++) {
            for (int j = 0; j < N - 1; j++) {
                if (A[j] > A[j + 1]) {
                    int p = 0;
                    while ((A[j] & (1 << p)) == 0 && (A[j + 1] & (1 << p)) == 0) {
                        p++;
                    }
                    A[j] ^= (1 << p);
                    A[j + 1] ^= (1 << p);
                    break;
                }
            }
        }
        for (int i = 0; i < N; i++) {
            printf("%d ", A[i]);
        }
        printf("\n");
    }
    return 0;
}

